def gen(rng, size):
    n = max(1, size)
    nums = []
    for _ in range(n):
        if rng.random() < 0.4:
            nums.append(6 * rng.randint(1, 166))
        else:
            nums.append(rng.randint(1, 1000))
    return [nums]

